    use super::*;

    #[test]
    fn irods_path_round_trip() {
        let json = r#""/testZone/home/irods/foo.txt""#;
        let p: IrodsPath = serde_json::from_str(json).unwrap();
        assert_eq!(p.as_str(), "/testZone/home/irods/foo.txt");
        assert_eq!(serde_json::to_string(&p).unwrap(), json);
    }

    #[test]
    fn irods_path_constructors() {
        assert_eq!(IrodsPath::new("/a/b").as_str(), "/a/b");
        assert_eq!(IrodsPath::from("/a/b").as_str(), "/a/b");
        assert_eq!(IrodsPath::from(String::from("/a/b")).as_str(), "/a/b");
    }

    #[test]
    fn data_object_minimal_round_trip() {
        let json = r#"{"collection":"/testZone/home/irods","data_object":"foo.txt"}"#;
        let d: DataObject = serde_json::from_str(json).unwrap();
        assert_eq!(d.collection, "/testZone/home/irods");
        assert_eq!(d.data_object, "foo.txt");
        assert_eq!(d.size, None);
        assert_eq!(d.checksum, None);
        assert_eq!(serde_json::to_string(&d).unwrap(), json);
    }

    #[test]
    fn data_object_with_size_and_checksum_round_trip() {
        let json = r#"{"collection":"/testZone/home/irods","data_object":"foo.txt","size":1024,"checksum":"d41d8cd98f00b204e9800998ecf8427e"}"#;
        let d: DataObject = serde_json::from_str(json).unwrap();
        assert_eq!(d.size, Some(1024));
        assert_eq!(d.checksum.as_deref(), Some("d41d8cd98f00b204e9800998ecf8427e"));
        assert_eq!(serde_json::to_string(&d).unwrap(), json);
    }

